/**
 * Calculates (base^exp) % mod
 * @param {bigint} base
 * @param {bigint} exp
 * @param {bigint} mod
 * @returns {bigint}
 */
const power = (base, exp, mod) => {
    let res = 1n;
    base %= mod;
    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2n;
    }
    return res;
};

/**
 * Calculates modular inverse using Fermat's Little Theorem: a^(M-2) mod M
 * @param {bigint} n
 * @param {bigint} mod
 * @returns {bigint}
 */
const modInverse = (n, mod) => {
    return power(n, mod - 2n, mod);
};

/**
 * Solves the problem: finds the number of ways to assign directions such that 
 * the person at pos sees exactly k people.
 * 
 * @param {number} n Total number of people.
 * @param {number} pos Position of the observing person.
 * @param {number} k Target number of visible people.
 * @returns {number} The count modulo 10^9 + 7.
 */
const solve = (n, pos, k) => {
    const MOD = 1000000007n;

    // The total number of independent choices contributing to visibility is N-1.
    // We need to choose K of these N-1 people to be visible.
    // The count is 2 * C(N-1, K) mod MOD.

    const N_prime = n - 1;
    const K_target = k;

    if (K_target < 0 || K_target > N_prime) {
        return 0;
    }

    if (N_prime < 0) { // Should only happen if n=0, but constraints say n>=1
        return 0;
    }

    // Precompute factorials up to N_prime
    const fact = new Array(N_prime + 1);
    fact[0] = 1n;
    for (let i = 1; i <= N_prime; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }

    // Function to calculate C(n, k) mod MOD
    const combinations = (n, k) => {
        if (k < 0 || k > n) {
            return 0n;
        }
        if (k === 0 || k === n) {
            return 1n;
        }
        if (k > n / 2) {
            k = n - k;
        }

        // C(n, k) = n! / (k! * (n-k)!)
        let numerator = fact[n];
        let denominator = (fact[k] * fact[n - k]) % MOD;

        let inverse_denominator = modInverse(denominator, MOD);

        return (numerator * inverse_denominator) % MOD;
    };

    // Calculate C(N-1, K)
    let combinations_nk = combinations(N_prime, K_target);

    // Total ways = 2 * C(N-1, K)
    let result = (2n * combinations_nk) % MOD;

    return Number(result);
};
