import scala.math.pow

object Solution {

    val MOD: Long = 1000000007L

    // Modular exponentiation: (base^exp) % mod
    def power(base: Long, exp: Long): Long = {
        var res: Long = 1
        var b: Long = base % MOD
        var e: Long = exp
        while (e > 0) {
            if (e % 2 == 1) {
                res = (res * b) % MOD
            }
            b = (b * b) % MOD
            e /= 2
        }
        res
    }

    // Modular inverse using Fermat's Little Theorem: a^(M-2) % M
    def modInverse(n: Long): Long = power(n, MOD - 2)

    // Precompute factorials up to maxN
    private var fact: Array[Long] = Array.empty[Long]
    private var invFact: Array[Long] = Array.empty[Long]
    private var maxPrecomputedN: Int = 0

    def precomputeFactorials(maxN: Int): Unit = {
        if (maxN <= maxPrecomputedN) return

        val newSize = maxN + 1
        val currentSize = maxPrecomputedN + 1

        val newFact = Array.fill(newSize)("0")
        val newInvFact = Array.fill(newSize)("0")

        // Copy previous values if possible, or start fresh
        if (currentSize > 0) {
            newFact := new Array[Long](newSize)
            newFact.take(currentSize) := fact.take(currentSize)
            newInvFact := new Array[Long](newSize)
            newInvFact.take(currentSize) := invFact.take(currentSize)
        }

        newFact(0) = 1
        for (i <- 1 until newSize) {
            newFact(i) = (newFact(i - 1) * i) % MOD
        }

        newInvFact(newSize - 1) = modInverse(newFact(newSize - 1))
        for (i <- newSize - 2 downto 0) {
            newInvFact(i) = (newInvFact(i + 1) * (i + 1)) % MOD
        }

        fact = newFact
        invFact = newInvFact
        maxPrecomputedN = maxN
    }

    // Combination function nCr % MOD
    def combinations(n: Long, r: Long): Long:
        if (r < 0 || r > n) return 0L
        val nInt = n.toInt
        val rInt = r.toInt

        precomputeFactorials(nInt)

        // nCr = n! / (r! * (n-r)!)
        var result: Long = fact(nInt)

        val invRFact = invFact(rInt)
        val invNRFact = invFact(nInt - rInt)

        result = (result * invRFact) % MOD
        result = (result * invNRFact) % MOD

        result

}

def n(N: Long): Long = N
def pos(P: Long): Long = P
def k(K: Long): Long = K

val solve: (Long, Long, Long) => Long = (N_val, P_val, K_val) => {
    // The result is 2 * C(N-1, K) mod M

    val nMinus1: Long = N_val - 1

    // Since N >= 1, N-1 >= 0. K is also guaranteed to be <= N-1 by problem constraints (if N > 1) or K=0 (if N=1).

    val combinationsValue: Long = Solution.combinations(nMinus1, K_val)

    // Total ways = 2 * C(N-1, K)
    var result: Long = (2L * combinationsValue) % Solution.MOD

    result
}
