import scala.annotation.tailrec

object Solution {
    val MOD: Long = 1000000007L

    // Precompute factorials up to MAX_N (N <= 10^5)
    val MAX_N = 100000
    val fact = new Array[Long](MAX_N + 1)

    // Initialize factorials
    lazy val initialized: Boolean = {
        if (fact(0) == 0) {
            fact(0) = 1
            for (i <- 1 to MAX_N) {
                fact(i) = (fact(i - 1) * i) % MOD
            }
            true
        } else false
    }

    def power(base: Long, exp: Long): Long = {
        var res: Long = 1
        var b: Long = base % MOD
        var e: Long = exp

        @tailrec
        def loop(): Long = if (e == 0) res else {
            val newRes = if (e % 2 == 1) (res * b) % MOD else res
            val newB = (b * b) % MOD
            loop(newRes, newB, e / 2)
        }

        // Helper wrapper to manage the state passing for tail recursion cleanly
        @tailrec
        def loop_tail(acc: Long, current_base: Long, current_exp: Long): Long = 
            if (current_exp == 0) acc
            else {
                var next_acc = acc
                var next_base = current_base
                var next_exp = current_exp

                if (current_exp % 2 == 1) {
                    next_acc = (next_acc * current_base) % MOD
